UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('wrist-rockers-palms-down', 'Hands closer to knees; small rocks; use animal cue: "bear paws."', 'No sex-based default; scale by wrist tolerance, shoulder history, body size, training age, hypermobility/stiffness profile, pain response, tumbling/ninja demands, pregnancy/postpartum status when relevant, and readiness that day.'),
  ('wrist-rockers-palms-up', 'Usually optional; use wrist circles instead if uncomfortable.', 'No sex-based default; smaller wrists or lower hand-loading history may need lower load.'),
  ('finger-pulses', '5–8 reps; make it a "spider fingers" game.', 'No sex-based default; scale by hand size, grip history, and wrist tolerance.'),
  ('scapular-push-up', 'Quadruped version only; cue "cat back with straight elbows."', 'No sex-based default; scale by upper-body strength and wrist/shoulder tolerance.'),
  ('quadruped-shoulder-circles', 'Use "shoulder clock" cue: 12, 3, 6, 9.', 'No sex-based default; scale by shoulder control and hand-support tolerance.'),
  ('wall-slides-with-lift-off', 'No band, no lift-off; slide only.', 'No sex-based default; scale by overhead range, trunk control, and shoulder history.'),
  ('band-external-rotation', 'Use no band first: "robot arms open/close."', 'No sex-based default; scale by shoulder history, band strength, and control.'),
  ('arm-circles', 'Use simple arm circles first; later teach controlled CARs.', 'No sex-based default; scale by shoulder control and mobility profile.'),
  ('bear-crawl-rock-back', 'Keep knees on floor and rock back from quadruped.', 'No sex-based default; scale by trunk control and hand-support tolerance.'),
  ('down-dog-to-plank-wave', 'Use bear rock-back instead; avoid long plank if form collapses.', 'No sex-based default; scale by shoulder/wrist load tolerance and trunk control.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

